// Entrada: body del webhook { message, history[], lang }
const input = $input.first().json;
const body = input.body || input;
const message = String(body.message || '').slice(0, 1000);
const history = Array.isArray(body.history) ? body.history.slice(-8) : [];
const lang = body.lang === 'en' ? 'en' : 'es';

// Catálogo REAL (compacto) servido por la web — para recomendar sin inventar
const catalog = await this.helpers.httpRequest({
  url: 'https://web-bochile.onrender.com/data/catalog.min.json',
  json: true,
});

const sys = [
  lang === 'en'
    ? 'You are Camila, a real-estate advisor at Bochile (Bahia Blanca, Argentina, since 1970). Warm, professional, concise. Reply in English.'
    : 'Sos Camila, asesora de Bochile (inmobiliaria de Bahia Blanca, desde 1970). Calida, profesional y concisa. Trata al usuario de USTED (formal). Responde en espanol.',
  'Solo podes recomendar propiedades del CATALOGO que te paso (son reales). NUNCA inventes propiedades, precios ni direcciones.',
  'Si el usuario busca algo, elegi hasta 3 ids del catalogo que mejor matcheen y devolvelos en "props". Si no aplica (saludo, pregunta general), props=[].',
  'No hay alquileres cargados (todos op="sale"). Si piden alquiler, avisa con honestidad y ofrece tomar sus datos por WhatsApp.',
  'Cuando tenga sentido, sugeri continuar por WhatsApp para coordinar con un asesor.',
  'RESPONDE EXCLUSIVAMENTE en JSON valido: {"text": string, "props": string[]}. Nada fuera del JSON.',
  'CATALOGO (JSON): ' + JSON.stringify(catalog),
].join('\n');

const messages = [{ role: 'system', content: sys }];
for (const h of history) {
  if (h && (h.role === 'user' || h.role === 'assistant') && h.content) {
    messages.push({ role: h.role, content: String(h.content).slice(0, 1000) });
  }
}
messages.push({ role: 'user', content: message });

return [{ json: { body: { model: 'gpt-4o-mini', temperature: 0.4, response_format: { type: 'json_object' }, messages } } }];

// Parsea la respuesta de OpenAI -> { text, props }
const res = $input.first().json;
let out = { text: '', props: [] };
try {
  const content = res.choices[0].message.content;
  const parsed = typeof content === 'string' ? JSON.parse(content) : content;
  out.text = String(parsed.text || '').trim();
  out.props = Array.isArray(parsed.props) ? parsed.props.map(String).slice(0, 3) : [];
} catch (e) {
  out.text = '';
}
if (!out.text) out.text = 'Disculpe, tuve un inconveniente. Puede escribirnos por WhatsApp y lo atendemos enseguida.';
return [{ json: out }];

